from opentelemetry.baggage import set_baggage, get_baggage
import fastapi

app = fastapi.FastAPI()

@app.middleware("http")
async def inject_conversation_context(request: fastapi.Request, call_next):
    conversation_id = request.headers.get("X-Conversation-ID")
    if conversation_id:
        # Baggage propagates through all child spans automatically
        token = set_baggage("conversation.id", conversation_id)
    return await call_next(request)

async def get_conversation_id() -> str | None:
    return get_baggage("conversation.id")
